# PagerDuty on-call schedule for agentic AI service — primary + secondary
# Requires: pagerduty/pagerduty Terraform provider

resource "pagerduty_schedule" "agent_primary" {
  name      = "Agent Service - Primary On-Call"
  time_zone = "UTC"

  layer {
    name                         = "Weekly Primary Rotation"
    start                        = "2025-08-04T09:00:00Z"
    rotation_virtual_start       = "2025-08-04T09:00:00Z"
    rotation_turn_length_seconds = 604800  # 7 days

    users = [
      pagerduty_user.alice.id,
      pagerduty_user.bob.id,
      pagerduty_user.carol.id,
      pagerduty_user.dave.id,
    ]
  }
}

resource "pagerduty_schedule" "agent_secondary" {
  name      = "Agent Service - Secondary On-Call"
  time_zone = "UTC"

  layer {
    name                         = "Weekly Secondary Rotation"
    start                        = "2025-08-04T09:00:00Z"
    rotation_virtual_start       = "2025-08-04T09:00:00Z"
    rotation_turn_length_seconds = 604800

    # Secondary is offset by one person in the list
    users = [
      pagerduty_user.bob.id,
      pagerduty_user.carol.id,
      pagerduty_user.dave.id,
      pagerduty_user.alice.id,
    ]
  }
}

resource "pagerduty_escalation_policy" "agent_service" {
  name      = "Agent Service Escalation Policy"
  num_loops = 2

  rule {
    escalation_delay_in_minutes = 30  # GenAI incidents need more time before escalation
    target {
      type = "schedule_reference"
      id   = pagerduty_schedule.agent_primary.id
    }
  }

  rule {
    escalation_delay_in_minutes = 20
    target {
      type = "schedule_reference"
      id   = pagerduty_schedule.agent_secondary.id
    }
  }
}

#!/usr/bin/env python3
"""Send shift reminders and handoff prompts via Slack. Run on a cron schedule."""

import os
import json
import requests
from datetime import datetime, timedelta, timezone

SLACK_WEBHOOK = os.environ["SLACK_ONCALL_WEBHOOK"]
PAGERDUTY_API_KEY = os.environ["PAGERDUTY_API_KEY"]
SCHEDULE_ID = os.environ["PAGERDUTY_SCHEDULE_ID"]


def get_current_oncall(schedule_id: str) -> dict:
    """Fetch who is currently on call from PagerDuty."""
    resp = requests.get(
        f"https://api.pagerduty.com/oncalls",
        headers={
            "Authorization": f"Token token={PAGERDUTY_API_KEY}",
            "Accept": "application/vnd.pagerduty+json;version=2",
        },
        params={"schedule_ids[]": schedule_id, "limit": 5},
        timeout=10,
    )
    resp.raise_for_status()
    return resp.json().get("oncalls", [])


def post_slack(message: str) -> None:
    requests.post(
        SLACK_WEBHOOK,
        json={"text": message},
        timeout=10,
    )


def check_and_notify():
    oncalls = get_current_oncall(SCHEDULE_ID)
    if not oncalls:
        return

    now = datetime.now(timezone.utc)
    for oncall in oncalls:
        shift_end_str = oncall.get("end")  # ISO8601
        if not shift_end_str:
            continue
        shift_end = datetime.fromisoformat(shift_end_str.replace("Z", "+00:00"))
        hours_until_end = (shift_end - now).total_seconds() / 3600
        user_name = oncall.get("user", {}).get("summary", "Unknown")
        user_email = oncall.get("user", {}).get("email", "")

        # 24-hour reminder to write handoff note
        if 23.5 < hours_until_end < 24.5:
            post_slack(
                f":memo: *Handoff Reminder* — @{user_name} your on-call shift ends in ~24h. "
                f"Please start your handoff note in #sre-oncall-handoffs: "
                f"open incidents, degraded services, anomalies, and model behavior notes."
            )

        # 1-hour reminder
        if 0.8 < hours_until_end < 1.2:
            post_slack(
                f":rotating_light: *Shift Ending Soon* — @{user_name} your shift ends in 1h. "
                f"Ensure your handoff note is complete and the incoming engineer is briefed."
            )


if __name__ == "__main__":
    check_and_notify()
